  var igrid = Matrix.getObject(arguments[0]);
 	var ctlTop = Matrix.getObject(arguments[1]);
 	var ctlBottom = Matrix.getObject(arguments[2]);
 	var splitterColor = arguments[3];
	var SPLITTER_COLOR = "#FF95B3D7";
	if(!igrid || !ctlTop || !ctlBottom) return;


	if(ctlTop.ZIndex <=  igrid.ZIndex){
		ctlTop.ZIndex =  igrid.ZIndex + 2;
    ctlTop.Update();
	}
	 ctlTop.Docking.Margin = "0,0,0,3";

	if(ctlBottom.ZIndex <=  igrid.ZIndex){
		ctlBottom.ZIndex =  igrid.ZIndex + 2;
    ctlBottom.Update();
	}
	ctlBottom.Docking.Margin = "0,3,0,0";
  igrid.Style.Type="Custom";
  igrid.Style.Border.LineType ="none";
  igrid.Update();

	if(splitterColor){
    splitterColor = splitterColor.trim();
		if(splitterColor.indexOf("#") == 0){
			SPLITTER_COLOR = "#FF" + splitterColor.substring(1,splitterColor.length);			
		}
	}
   var h1 = ctlTop.Height  + 3;
   var h2 = 23;//ctlBottom.Height;
   	var json = {
			"DefaultFontName":"맑은 고딕"
			,"DefaultFontSize":15
			,"OriginFontSize":11
			,"Styles":{
				"S0":{"text-align":"left","vertical-align":"middle"},
				"S1":{"border-bottom":"Thick," + SPLITTER_COLOR},
				"S2":{"border-top":"Thick," + SPLITTER_COLOR}
			},
			"Tables":[
			{
				"FreezePanes":{"Row":-1, "Column":-1} 
				,"Columns":[
					{"Index": 1 , "width":502,"W":62.13 , "Unit":1 }
					]
				, "Rows":[
					{"R":1,"Height":h1,"height":h1,"Resize":2,"H":122.25 
					,"Cells":[
					{"Range":"A1","R":1,"C":1,"class":"S1","Type":"Empty","CTL":ctlTop.Name}
					]}
					,{"R":2,"Height":h2,"height":h2,"Resize":2,"H":122.25,"Unit":1
					,"Cells":[
					{"Range":"A2","R":2,"C":1,"class":"S2","Type":"Empty","CTL":ctlBottom.Name}
					]}
					]
					,"UsageExpand":false
					,"HasPerCol":true
					,"HasPerRow":true

				}
			]
		};   
	igrid.ApplyDataSource(json);

   	var args =  arguments[arguments.length -1];
	if(args != null && args.Id){
		if(Matrix.getObject(args.Id) != null){
		alert("이 모듈은 컨트롤의 이벤트에 등록 하실 수 없습니다.\n모듈로 사용하시거나 Report Open 이벤트에서 사용하시기 바랍니다.");
		return;
		}
	}
	var olap =  Matrix.getObject(arguments[0]);
	if(!olap) return;
	var grid =  Matrix.getObject(arguments[1]);
	if(!olap) return;
	olap.OnDataCellDoubleClick = function(sender, args){ 	

		var ds = Matrix.getControlDataSource(olap.Name);
		if(ds){
			if(ds.useMeta == "True"){
				  var xml = olap.getDrillToDetailXml(args.DataCell);
				  Matrix.DrillToDetail(olap, xml, grid.Name);
			}else{
				  olap.ExecuteDrillToDetail(args.DataCell ,grid.Name);
			}
		}	

	};
